#include <bits/stdc++.h>
using namespace std;
int n,c[100005],dp[100005][2],ans;
bool to[100005];
vector<int> g[100005];
void dfs(int x){
    to[x]=1;//标记是否被访问过
    int len=g[x].size();
    dp[x][0]=1;//初始化为 1
    priority_queue<int> q;
    for(int i=0;i<len;i++)
        if(!to[g[x][i]]){
        	dfs(g[x][i]);//要先进行 dfs
        	if(c[x]!=c[g[x][i]]){//如果颜色不同
        		dp[x][0]=max(dp[x][0],dp[g[x][i]][0]+1);
            	q.push(dp[g[x][i]][0]);
              //赋值 dp[x][0] 并将其放入堆中
            }
        }
    if(q.size()>1){
      //如果数量大于 1，赋值 dp[x][1]
    	int last=q.top();
    	q.pop();
    	dp[x][1]=1+last+q.top();
	}
    ans=max(ans,max(dp[x][0],dp[x][1]));//统计答案
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&c[i]);
    for(int i=1;i<n;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    dfs(1);
    printf("%d",ans);
    return 0;
}
